let maxPagesName = {
    "seriesMaxPages": "系列最大页码",
    "novelsMaxPages": "单篇最大页码"
}

function showMaxPages() {
    let keys = Object.keys(maxPagesName)
    let key = getFromCache("maxPagesKey")

    // 切换列表
