}

function getSeries() {
    let novels = []
    let name = String(java.get("keyword"))
    let maxPages = getFromCache("maxPages")  // 仅默认搜索使用
    if (!maxPages) {
        maxPages = getFromCache("seriesMaxPages")  // 搜索标签使用
        if (!maxPages) maxPages = 1
        putInCache("seriesMaxPages", maxPages)
    }
    java.log(`📄 搜索系列最大页码：${maxPages}`)

