    cache.put(urlSearchSeries(name, 1), result, cacheSaveSeconds)  // 加入缓存
    for (let page = Number(java.get("page")) + 1; page <= lastPage && page <= maxPages; page++) {
        novels = novels.concat(search(name,"series", page).data)
