	link=links[i];
	aAttrs=String(link).match(regex);
	var text='',decUrl='';
	for (key of aAttrs){
		value=link.attr(key);
		value.includes("L2J")?decUrl=java.base64Decode(value):text=value.trim()
	}
	liAttrs=String(result[i]).match(regex);
	list.push({
		text:text,
		href:decUrl,
		num:result[i].attr(liAttrs[1])
	});
}
list.sort((a,b)=>a.num-b.num)

